ee:message.ee:set-payload:
%dw 2.0
output application/json
var transmissionErrors = vars.transmissionData
var messageErrors = vars.messagesData
---
{
  "blocks": flatten([
    // Header
    {
      "type": "header",
      "text": {
        "type": "plain_text",
        "text": "🚨 Apm Error Alert",
        "emoji": true
      }
    },

    // Transmission Errors Heading (only if there are errors)


    // Transmission Errors Loop
    (transmissionErrors default []) flatMap (err ,idx) -> 
      {
        "type": "section",
        "text": {
          "type": "mrkdwn",
          "text": "*Transmission Error " ++ (idx + 1) as String ++ "*"
        },
        "fields": [
          { "type": "mrkdwn", "text": "*Direction:* " ++ (err.direction default "N/A") },
          { "type": "mrkdwn", "text": "*Partner From:* " ++ (err.partnerFrom default "N/A") },
          { "type": "mrkdwn", "text": "*Partner To:* " ++ (err.partnerTo default "N/A") },
          { "type": "mrkdwn", "text": "*Business Key:* " ++ (err.businessKey default "N/A") },
          { "type": "mrkdwn", "text": "*Error:* " ++ (err.errorMessage default "N/A") }
        ]
      },
      { "type": "divider" },

    // Message Errors Heading (only if there are errors)

    // Message Errors Loop
    (messageErrors default []) flatMap (err,idx) -> 
      {
        "type": "section",
        "text": {
          "type": "mrkdwn",
          "text": "*Message Error " ++ (idx + 1) as String ++ "*"
        },
        "fields": [
          { "type": "mrkdwn", "text": "*Message Type:* " ++ (err.messageType default "N/A") },
          { "type": "mrkdwn", "text": "*Direction:* " ++ (err.direction default "N/A") },
          { "type": "mrkdwn", "text": "*Partner From:* " ++ (err.partnerFrom default "N/A") },
          { "type": "mrkdwn", "text": "*Partner To:* " ++ (err.partnerTo default "N/A") },
          { "type": "mrkdwn", "text": "*Business Key:* " ++ (err.businessKey default "N/A") }
        ]
      },
      { "type": "divider" }
    ,

    // Context Section
    {
      "type": "context",
      "elements": [
        {
          "type": "mrkdwn",
          "text": "🔎 Please investigate the logs for further details."
        }
      ]
    }
  ])
}
